import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty grid when given empty grid -- []");
  it.todo("should kill a single cell with 0 neighbors (Rule 1: underpopulation) -- [(0,0)] → []");
  it.todo("should kill two adjacent cells each with 1 neighbor (Rule 1: underpopulation) -- [(0,1),(1,1)] → []");
  it.todo("should keep alive a cell with exactly 2 neighbors (Rule 2: survival) -- block corner cell survives");
  it.todo("should keep alive a cell with exactly 3 neighbors (Rule 2: survival) -- [(0,1),(1,1),(2,1),(1,2)] center (1,1) survives");
  it.todo("should kill a cell with more than 3 neighbors (Rule 3: overpopulation) -- [(0,0),(1,0),(2,0),(1,1),(0,2),(1,2),(2,2)] center (1,1) dies");
  it.todo("should birth a dead cell with exactly 3 neighbors (Rule 4: reproduction) -- [(0,0),(1,0),(0,1)] → (1,1) born");
  it.todo("should leave block still life unchanged -- [(0,0),(1,0),(0,1),(1,1)] → same");
  it.todo("should transform blinker from vertical to horizontal -- [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
  it.todo("should return blinker to original after two generations -- [(0,0),(0,1),(0,2)] → gen1 → [(0,0),(0,1),(0,2)]");
  it.todo("should handle negative coordinates correctly -- cell at (-1,-1) with 0 neighbors dies");
});

